    # Check if the matrix is square
    if len(matrix) != len(matrix[0]):
        return False

    # Calculate the sum of the first row
    row_sum = sum(matrix[0])

    # Check if all rows have the same sum
    for row in matrix:
        if sum(row) != row_sum:
            return False

    # Check if all columns have the same sum
    for col in range(len(matrix[0])):
        col_sum = sum(matrix[row][col] for row in range(len(matrix)))
        if col_sum != row_sum:
            return False

    # Check if the main diagonal has the same sum
    diag_sum = sum(matrix[i][i] for i in range(len(matrix)))
    if diag_sum != row_sum:
        return False

    # Check if the anti-diagonal has the same sum
    anti_diag_sum = sum(matrix[i][len(matrix) - 1 - i] for i in range(len(matrix)))
    if anti_diag_sum != row_sum:
        return False

    return True

